import { useEffect, useState } from "react"
function Crypto() {
  let [cryptodata, changecryptodata] = useState([])
  useEffect(() => {
    async function fetchcoins() {
      let cryptodataarr = ["bitcoin", "ethereum", "bnb"]
      let res = cryptodataarr.map(async(item) => {
        setTimeout(async () => {
          let fetched = await fetch(`https://api.coingecko.com/api/v3/coins/${item}/market_chart?vs_currency=usd&days=7&interval=daily`)
          let fetchedjson = await fetched.json()
          changecryptodata([...cryptodata, fetchedjson])
        }, 1000)
      })

    }
    console.log(cryptodata)
    fetchcoins()
  }, [])
